```plantuml
@startuml
title Modulo-matrícula/Informática

skinparam classAttributeIconSize 0

class "Matrícula" as Matricula {
  -cliente: Client
  -tempo: Int
  -quadra: Turma
}

class "Aluno" as Aluno {
  -id: Int
  -nome: String
  -locação: List<Matrícula>
}

class "controleNúmeroMatrícula" as ControleNumeroMatricula {
  -quantidade: Int
}

class "Curso" as Curso {
  -nome: String
  -quadra: List<Turma>
}

class "Turma" as Turma {
  -numero: Int
  -aluguel: Matrícula
  -ginasio: Curso
}

Matricula "0..*" *-- "1" Aluno : composição 1
Curso "1..*" --* "1" Turma : composição 1
Matricula "1..*" *-- "1" Turma : composição

Turma ..|> ControleNumeroMatricula

@enduml
```
